#version 330 core

// Atributos de entrada (un vertice por esquina)
in vec3 position;
in vec3 normal;
in vec3 color;

// Uniforms de transformacion
uniform mat4 u_model;       // transformacion local -> mundo
uniform mat4 u_view;        // mundo -> camara
uniform mat4 u_projection;  // camara -> clip
uniform mat3 u_normal_mat;  // para transformar normales (inversa-transpuesta del modelo)

// Salidas hacia el fragment shader
out vec3 v_world_pos;
out vec3 v_world_normal;
out vec3 v_color;

void main() {
    vec4 world_pos = u_model * vec4(position, 1.0);
    v_world_pos = world_pos.xyz;
    v_world_normal = normalize(u_normal_mat * normal);
    v_color = color;

    gl_Position = u_projection * u_view * world_pos;
}

#version 330 core

// Entradas desde el vertex shader
in vec3 v_world_pos;
in vec3 v_world_normal;
in vec3 v_color;

// Uniform de iluminacion
uniform vec3 u_light_dir;   // direccion de la luz (hacia la fuente)
uniform vec3 u_light_color; // color de la luz
uniform vec3 u_ambient;     // termino ambiente

out vec4 frag_color;

void main() {
    vec3 n = normalize(v_world_normal);
    vec3 l = normalize(u_light_dir);

    // Componente difusa (Lambert) con limite inferior en 0
    float diff = max(dot(n, l), 0.0);

    // Componente ambiental + difusa
    vec3 lighting = u_ambient + u_light_color * diff;

    vec3 result = lighting * v_color;
    frag_color = vec4(result, 1.0);
}

