Hmm. The triangle is not visible with our shader, but it was with the simple shader. Let me check what's different:

The simple shader I used before:
```glsl
#version 330 core
in vec3 position;
in vec3 color;
out vec3 fcolor;
void main() {
    gl_Position = vec4(position, 1.0);
    fcolor = color;
}
```

The full shader I have:
```glsl
#version 330 core
in vec3 position;
in vec3 normal;
in vec3 color;
uniform mat4 u_model;
uniform mat4 u_view;
uniform mat4 u_projection;
uniform mat4 u_normal_mat;
out vec3 v_world_pos;
out vec3 v_world_normal;
out vec3 v_color;
void main() {
    vec4 world_pos = u_model * vec4(position, 1.0);
    v_world_pos = world_pos.xyz;
    mat3 n3 = mat3(u_normal_mat);
    v_world_normal = normalize(n3 * normal);
    v_color = color;
    gl_Position = u_projection * u_view * world_pos;
}
```

Fragment shader:
```glsl
#version 330 core
in vec3 v_world_pos;
in vec3 v_world_normal;
in vec3 v_color;
uniform vec3 u_light_dir;
uniform vec3 u_light_color;
uniform vec3 u_ambient;
out vec4 frag_color;
void main() {
    vec3 n = normalize(v_world_normal);
    vec3 l = normalize(u_light_dir);
    float diff = max(dot(n, l), 0.0);
    vec3 lighting = u_ambient + u_light_color * diff;
    vec3 result = lighting * v_color;
    frag_color = vec4(result, 1.0);
}
```

Wait! I see a potential issue. When the normal is in the +Z direction and the light direction is also (0, 0, 1), the diffuse is 1.0. With ambient 0.5 and light color (1,1,1), the result should be 1.5 * (1, 0, 0) = (1.5, 0, 0) which clamps to (1, 0, 0). So the triangle should appear red.

Let me check if there's a GLSL issue. Maybe the mat3 conversion is failing in some way. Let me try a simpler shaderto debug:

